// src/toolbar.js
import { DraggableNode } from "./draggableNode";

export const PipelineToolbar = () => {
  return (
    <div style={{ 
      padding: "10px", 
      backgroundColor: "#1a1f2e",
      borderBottom: "1px solid #2d3748"
    }}>
      <div style={{ 
        display: "flex", 
        gap: "10px",
        alignItems: "center"
      }}>
        <span style={{ color: "#fff", fontWeight: "600", marginRight: "10px" }}>Nodes:</span>

        <DraggableNode 
          type="inputNode" 
          label="Input"
          nodeProps={{
            data: { 
              label: "Input",
              inputName: "input_1",
              inputType: "Text"
            }
          }}
        />

        <DraggableNode 
          type="llmNode" 
          label="LLM"
          nodeProps={{
            data: { 
              label: "LLM"
            }
          }}
        />

        <DraggableNode 
          type="textNode" 
          label="Text"
          nodeProps={{
            data: { 
              label: "Text",
              text: "{{input}}"
            }
          }}
        />

        <DraggableNode 
          type="outputNode" 
          label="Output"
          nodeProps={{
            data: { 
              label: "Output",
              outputName: "output_1",
              outputType: "Text"
            }
          }}
        />

        <DraggableNode
          type="deleteNode"
          label="Delete"
          nodeProps={{
            className: "delete-node",
            data: { 
              label: "Delete Node",
              candidates: [], 
              onDelete: () => console.log("Delete function will be set when dropped"),
              canDeleteTool: false 
            },
          }}
        />
      </div>
    </div>
  );
};
